-- ========================================
-- BEGIN V6__create_activity_and_points_tables.sql
-- ========================================

-- V6: Create activity_logs and point_transactions tables for Activity History feature

-- ========================================
-- 1. Activity Logs Table
-- ========================================
CREATE TABLE IF NOT EXISTS activity_logs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,

-- Activity type: CHECK_IN, CHECK_OUT, BOOKING_SUCCESS, BOOKING_CANCEL, NFC_CONFIRM, GATE_ENTRY, NO_SHOW
activity_type VARCHAR(50) NOT NULL,

-- Activity details
title VARCHAR(255) NOT NULL, -- e.g., "Check-in thành công"
description TEXT, -- e.g., "Khu yên tỉnh - Ghế A15"

-- Optional references
reservation_id UUID REFERENCES reservations (reservation_id) ON DELETE SET NULL,
seat_code VARCHAR(20),
zone_name VARCHAR(100),

-- Duration for check-out activities (in minutes)
duration_minutes INTEGER,

-- Metadata
created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() );

CREATE INDEX IF NOT EXISTS idx_activity_logs_user_id ON activity_logs (user_id);

CREATE INDEX IF NOT EXISTS idx_activity_logs_created_at ON activity_logs (created_at DESC);

CREATE INDEX IF NOT EXISTS idx_activity_logs_type ON activity_logs (activity_type);

-- ========================================
-- 2. Point Transactions Table
-- ========================================
CREATE TABLE IF NOT EXISTS point_transactions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,

-- Point change: positive = credit, negative = debit
points INTEGER NOT NULL,

-- Transaction type: REWARD, PENALTY, WEEKLY_BONUS, NO_SHOW_PENALTY, CHECK_OUT_LATE_PENALTY
transaction_type VARCHAR(50) NOT NULL,

-- Details
title VARCHAR(255) NOT NULL, -- e.g., "Thưởng: Tuần học chăm chỉ"
description TEXT, -- e.g., "Hoàn thành 10 giờ học trong tuần"

-- Balance after this transaction
balance_after INTEGER,

-- Optional reference to activity that caused this
activity_log_id UUID REFERENCES activity_logs (id) ON DELETE SET NULL,

-- Metadata
created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW() );

CREATE INDEX IF NOT EXISTS idx_point_transactions_user_id ON point_transactions (user_id);

CREATE INDEX IF NOT EXISTS idx_point_transactions_created_at ON point_transactions (created_at DESC);

CREATE INDEX IF NOT EXISTS idx_point_transactions_type ON point_transactions (transaction_type);

-- ========================================
-- END V6__create_activity_and_points_tables.sql
-- ========================================

-- ========================================
-- BEGIN V7__add_user_auth_fields.sql
-- ========================================

-- V7: Add user authentication fields for username/password login
-- This migration adds support for traditional email/password authentication

-- ========================================
-- Rename student_code to user_code
-- ========================================
ALTER TABLE users RENAME COLUMN student_code TO user_code;

-- ========================================
-- Add new authentication and profile fields
-- ========================================
-- Username for login (can be email or custom username)
ALTER TABLE users ADD COLUMN IF NOT EXISTS username VARCHAR(50);

-- Password hash (BCrypt encoded)
ALTER TABLE users ADD COLUMN IF NOT EXISTS password VARCHAR(255);

-- Date of birth
ALTER TABLE users ADD COLUMN IF NOT EXISTS dob DATE;

-- Phone number
ALTER TABLE users ADD COLUMN IF NOT EXISTS phone VARCHAR(20);

-- Avatar URL
ALTER TABLE users ADD COLUMN IF NOT EXISTS avt_url TEXT;

-- Flag to check if user has changed default password
ALTER TABLE users
ADD COLUMN IF NOT EXISTS password_changed BOOLEAN DEFAULT FALSE;

-- ========================================
-- Set default username from user_code for existing users
-- ========================================
UPDATE users SET username = user_code WHERE username IS NULL;

-- ========================================
-- Add unique constraint on username
-- ========================================
DO $$
BEGIN
    ALTER TABLE users ADD CONSTRAINT users_username_unique UNIQUE (username);
EXCEPTION WHEN duplicate_object THEN
    NULL;
END $$;

-- ========================================
-- Add index for faster username lookup
-- ========================================
CREATE INDEX IF NOT EXISTS idx_users_username ON users (username);

-- ========================================
-- END V7__add_user_auth_fields.sql
