-- ============================================================
-- V31: Create missing entity tables and add missing columns
--
-- Audit found these JPA entities have no corresponding
-- CREATE TABLE in any Flyway migration:
--   1. ai_config
--   2. ai_knowledge_stores
--   3. ai_materials
--   4. ai_material_items
--   5. chat_sessions (AI chat)
--   6. chat_messages (AI chat)
