-- ========================================
-- BEGIN V55__recover_layout_large_object_payloads.sql
-- ========================================

UPDATE layout_drafts d
SET snapshot_json = convert_from(lo_get(d.snapshot_json::oid), 'UTF8')
WHERE d.snapshot_json ~ '^[0-9]+$'
  AND EXISTS (
      SELECT 1
      FROM pg_largeobject_metadata m
      WHERE m.oid = d.snapshot_json::oid
  );

UPDATE layout_history h
SET snapshot_json = convert_from(lo_get(h.snapshot_json::oid), 'UTF8')
WHERE h.snapshot_json ~ '^[0-9]+$'
  AND EXISTS (
      SELECT 1
      FROM pg_largeobject_metadata m
      WHERE m.oid = h.snapshot_json::oid
  );

UPDATE layout_history h
SET summary = convert_from(lo_get(h.summary::oid), 'UTF8')
WHERE h.summary ~ '^[0-9]+$'
  AND EXISTS (
      SELECT 1
      FROM pg_largeobject_metadata m
      WHERE m.oid = h.summary::oid
  );

-- ========================================
-- END V55__recover_layout_large_object_payloads.sql
-- ========================================

-- ========================================
-- BEGIN V56__scope_layout_drafts_per_staff.sql
-- ========================================

DELETE FROM layout_drafts
WHERE updated_by_user_id IS NULL;

DELETE FROM layout_drafts older
USING layout_drafts newer
WHERE older.updated_by_user_id = newer.updated_by_user_id
  AND older.draft_id < newer.draft_id;

CREATE UNIQUE INDEX IF NOT EXISTS ux_layout_drafts_updated_by_user_id
ON layout_drafts(updated_by_user_id)
WHERE updated_by_user_id IS NOT NULL;

-- ========================================
-- END V56__scope_layout_drafts_per_staff.sql
